async (params, browser) => {
  // Open Strava search
  await browser.open(`https://www.strava.com/athletes/search?utf8=%E2%9C%93&text=${params.query}`)

  // Wait for results
  await browser.waitForSelector('.athlete-list, .search-results, .content', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('.athlete-list li, .search-results .row, .text-headline a[href*="/athletes/"]').forEach((el, i) => { if (i < 15) { const nameEl = el.querySelector('a[href*="/athletes/"], .text-headline'); const locEl = el.querySelector('.location, .text-caption'); results.push({ name: nameEl?.textContent?.trim() || '', url: nameEl?.href || '', location: locEl?.textContent?.trim() || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
